        #region Constructor

        /// <summary>
        /// Initializes a new instance of the <see cref="FinancialViewModel"/> class and generate datasources for the financial series.
        /// </summary>
        public FinancialViewModel()
        {
            MsftStockData = GenerateColection(msftStockSource);
            NvdaStockData = GenerateColection(nvdaStockSource);
        }

        #endregion

        #region Methods

        internal void SetRange(string range)
        {
            switch (range)
            {
                case "3m":
                    ScrollingDelta = 3;
                    break;

                case "6m":
                    ScrollingDelta = 6;
                    break;
            }
        }

        ObservableCollection<FinancialDataModel> GenerateColection(string dataSource)
        {
            string[] rows = dataSource.Split(new[] { ';' }, StringSplitOptions.RemoveEmptyEntries);
            ObservableCollection<FinancialDataModel> collection = new();

            foreach (string row in rows)
            {
                string[] columns = row.Trim().Split('\t');
                if (columns.Length >= 5)
                {
                    FinancialDataModel item = new(
                        GetDateTime(columns[0]),
                        GetDouble(columns[2]), // High
                        GetDouble(columns[3]), // Low
                        GetDouble(columns[1]), // Open
                        GetDouble(columns[4])  // Close
                    );
                    collection.Add(item);
                }
            }

            return collection;
        }

        double GetDouble(string text)
